// Time Crystals — Rosette of Pulsing Polygons
// Adapted from GenerativeArtGallery / artwork16

let tcCrystals = [];
let tcPrevCount = '';
let tcPrevVerts = '';

function tcBuild(count, vMin, vMax) {
  let crysts = [];
  let rOuter = 155;
  for (let i = 0; i < count; i++) {
    let angle = i * Math.PI * 2 / count;
    let radius = rOuter * (0.7 + 0.3 * Math.sin(i * 1.7));
    let verts = Math.floor(Math.random() * (vMax - vMin + 1)) + vMin;
    crysts.push({
      cx: Math.cos(angle) * radius,
      cy: Math.sin(angle) * radius,
      size: 30 + Math.random() * 30,
      verts: verts,
      vAngles: Array.from({length: verts}, function(_, j) { return j * Math.PI * 2 / verts; }),
      baseHue: (angle * 180 / Math.PI + 360) % 360,
      tPhase: Math.random() * Math.PI * 2,
      tSpeed: 0.01 + Math.random() * 0.014,
      rot: Math.random() * Math.PI * 2,
      rotSpd: (Math.random() - 0.5) * 0.014
    });
  }
  return crysts;
}

p.setup = function() {
  p.createCanvas(400, 400, p.WEBGL);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.frameRate(30);
  tcCrystals = tcBuild(24, 4, 6);
};

p.draw = function() {
  let countStr = p.getSynthVar('crystal_count') || 'medium';
  let vertStr = p.getSynthVar('vertex_range') || 'balanced';
  let colorStr = p.getSynthVar('color_mode') || 'spectrum';
  let pulseStr = p.getSynthVar('pulse_speed') || 'moderate';

  let count = countStr === 'few' ? 12 : countStr === 'medium' ? 24 : 48;
  let vMin = vertStr === 'sharp' ? 3 : vertStr === 'balanced' ? 4 : 5;
  let vMax = vertStr === 'sharp' ? 4 : vertStr === 'balanced' ? 6 : 8;
  let pulseSpd = pulseStr === 'gentle' ? 0.6 : pulseStr === 'moderate' ? 1 : 2;

  if (countStr !== tcPrevCount || vertStr !== tcPrevVerts) {
    tcCrystals = tcBuild(count, vMin, vMax);
    tcPrevCount = countStr;
    tcPrevVerts = vertStr;
  }

  p.background(240, 20, 6);

  for (let i = 0; i < tcCrystals.length; i++) {
    let c = tcCrystals[i];
    c.rot += c.rotSpd;
    c.tPhase += c.tSpeed * pulseSpd;

    let hue;
    if (colorStr === 'spectrum') hue = (c.baseHue + 60 * Math.sin(c.tPhase)) % 360;
    else if (colorStr === 'cool') hue = (200 + 35 * Math.sin(c.tPhase + i * 0.3)) % 360;
    else if (colorStr === 'warm') hue = (20 + 30 * Math.sin(c.tPhase + i * 0.3)) % 360;
    else if (colorStr === 'ember') hue = (8 + 22 * Math.abs(Math.sin(c.tPhase))) % 360;
    else hue = (220 + 15 * Math.sin(c.tPhase * 0.5)) % 360;

    let scOsc = 1 + 0.12 * Math.sin(c.tPhase * 1.4);

    p.push();
    p.translate(c.cx, c.cy, 0);
    p.rotateZ(c.rot);
    p.scale(scOsc);

    p.fill(hue, 80, 68, 85);
    p.stroke((hue + 30) % 360, 70, 40, 70);
    p.strokeWeight(1.5);
    p.beginShape();
    for (let j = 0; j < c.verts; j++) {
      let a = c.vAngles[j];
      let r = c.size * (0.92 + 0.12 * Math.sin(c.tPhase + a * 2));
      p.vertex(Math.cos(a) * r, Math.sin(a) * r, 0);
    }
    p.endShape(p.CLOSE);

    p.fill((hue + 180) % 360, 55, 42, 70);
    p.noStroke();
    p.beginShape();
    for (let j = 0; j < c.verts; j++) {
      let a = c.vAngles[j] + Math.PI / c.verts;
      let r = c.size * 0.44 * (0.9 + 0.1 * Math.sin(c.tPhase * 1.3 + a));
      p.vertex(Math.cos(a) * r, Math.sin(a) * r, 0);
    }
    p.endShape(p.CLOSE);

    p.pop();
  }
};
